targetCode.css:
body {
  font-family: system-ui, sans-serif;
  margin: 0;
  background: #f1f3f5;
}

.layout {
  display: grid;
  grid-template-columns: 200px 1fr;
  grid-template-rows: auto 1fr auto;
  grid-template-areas:
    'header header'
    'sidebar content'
    'footer footer';
  min-height: 100vh;
}

header { grid-area: header; background: #264653; color: white; padding: 16px; text-align: center; }
footer { grid-area: footer; background: #264653; color: white; padding: 16px; text-align: center; }
aside { grid-area: sidebar; background: #2a9d8f; color: white; padding: 16px; }
main { grid-area: content; background: white; padding: 16px; }
